package com.example.samlsp.saml;

import org.opensaml.core.xml.XMLObject;
import org.opensaml.core.xml.io.UnmarshallingException;
import org.opensaml.core.xml.util.XMLObjectSupport;
import org.opensaml.saml.saml2.core.Assertion;
import org.opensaml.saml.saml2.core.Response;
import org.opensaml.security.credential.BasicX509Credential;
import org.opensaml.security.credential.Credential;
import org.opensaml.xmlsec.signature.support.SignatureException;
import org.opensaml.xmlsec.signature.support.SignatureValidator;
import org.w3c.dom.Document;
import org.w3c.dom.Element;

import javax.xml.parsers.DocumentBuilderFactory;
import java.io.ByteArrayInputStream;
import java.nio.charset.StandardCharsets;
import java.security.cert.X509Certificate;
import java.time.Instant;
import java.util.Base64;
import java.util.List;
import java.util.Optional;

public class SamlResponseValidator {

    private final SamlProperties props;
    private final X509Certificate idpCert;

    public SamlResponseValidator(SamlProperties props) {
        this.props = props;
        this.idpCert = PemUtils.parseCertificate(props.getIdpSigningCertPem());
    }

    public ValidatedSaml validatePostResponse(String samlResponseBase64) {
        try {
            byte[] decoded = Base64.getDecoder().decode(samlResponseBase64);
            Document doc = DocumentBuilderFactory.newInstance().newDocumentBuilder()
                    .parse(new ByteArrayInputStream(decoded));
            Element element = doc.getDocumentElement();

            Response response = SamlBuilders.unmarshall(element);

            if (props.isWantResponsesSigned() && response.getSignature() != null) {
                validateSignature(response.getSignature(), idpCert);
            }

            List<Assertion> assertions = response.getAssertions();
            if (assertions == null || assertions.isEmpty()) {
                throw new IllegalStateException("No assertions in response");
            }

            Assertion assertion = assertions.get(0);

            if (props.isWantAssertionsSigned() && assertion.getSignature() != null) {
                validateSignature(assertion.getSignature(), idpCert);
            }

            String subjectNameId = Optional.ofNullable(assertion.getSubject())
                    .map(s -> s.getNameID())
                    .map(n -> n.getValue())
                    .orElse(null);

            Instant notOnOrAfter = Optional.ofNullable(assertion.getConditions())
                    .map(c -> c.getNotOnOrAfter())
                    .orElse(null);

            if (notOnOrAfter != null && Instant.now().isAfter(notOnOrAfter)) {
                throw new IllegalStateException("Assertion expired");
            }

            return new ValidatedSaml(subjectNameId, response.getID(), assertion.getID());
        } catch (Exception e) {
            throw new IllegalStateException("Invalid SAMLResponse", e);
        }
    }

    private void validateSignature(org.opensaml.xmlsec.signature.Signature signature, X509Certificate cert)
            throws SignatureException {
        Credential cred = new BasicX509Credential(cert);
        SignatureValidator.validate(signature, cred);
    }

    public record ValidatedSaml(String subjectNameId, String responseId, String assertionId) {}
}

package com.example.samlsp.web;

import com.example.samlsp.saml.PemUtils;
import com.example.samlsp.saml.SamlProperties;
import org.springframework.http.MediaType;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import java.security.cert.X509Certificate;
import java.util.Objects;

@RestController
public class SamlMetadataController {

    private final SamlProperties props;

    public SamlMetadataController(SamlProperties props) {
        this.props = props;
    }

    @GetMapping(value = "/saml/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public String metadata() {
        X509Certificate spCert = null;
        if (props.getSpSigningCertPem() != null && !props.getSpSigningCertPem().isBlank()) {
            spCert = PemUtils.parseCertificate(props.getSpSigningCertPem());
        }

        String certB64 = spCert == null ? "" :
                java.util.Base64.getEncoder().encodeToString(spCert.getEncoded());

        String keyDescriptor = spCert == null ? "" :
                """
                <md:KeyDescriptor use="signing">
                  <ds:KeyInfo xmlns:ds="http://www.w3.org/2000/09/xmldsig#">
                    <ds:X509Data>
                      <ds:X509Certificate>%s</ds:X509Certificate>
                    </ds:X509Data>
                  </ds:KeyInfo>
                </md:KeyDescriptor>
                """.formatted(certB64);

        return """
                <md:EntityDescriptor xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
                                     entityID="%s">
                  <md:SPSSODescriptor AuthnRequestsSigned="%s"
                                     WantAssertionsSigned="%s"
                                     protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
                    %s
                    <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:persistent</md:NameIDFormat>
                    <md:AssertionConsumerService Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
                                                Location="%s"
                                                index="0"
                                                isDefault="true"/>
                  </md:SPSSODescriptor>
                </md:EntityDescriptor>
                """.formatted(
                escapeXml(props.getEntityId()),
                props.getSpSigningKeyPem() != null && !props.getSpSigningKeyPem().isBlank(),
                props.isWantAssertionsSigned(),
                keyDescriptor,
                escapeXml(props.getAcsUrl())
        );
    }

    private static String escapeXml(String s) {
        if (s == null) return "";
        return s.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
                .replace("\"", "&quot;").replace("'", "&apos;");
    }
}

package com.example.samlsp.web;

import com.example.samlsp.saml.PemUtils;
import com.example.samlsp.saml.SamlBuilders;
import com.example.samlsp.saml.SamlProperties;
import jakarta.servlet.http.HttpServletResponse;
import org.opensaml.saml.saml2.core.AuthnRequest;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.io.IOException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.security.PrivateKey;
import java.security.cert.X509Certificate;

@RestController
public class SamlSsoController {

    private final SamlProperties props;

    public SamlSsoController(SamlProperties props) {
        this.props = props;
    }

    @GetMapping("/saml/login")
    public void login(@RequestParam(value = "relayState", required = false) String relayState,
                      HttpServletResponse response) throws IOException {
        if (relayState == null || relayState.isBlank()) relayState = props.getDefaultRelayState();

        AuthnRequest req = SamlBuilders.buildAuthnRequest(props, relayState);

        if (props.getSpSigningKeyPem() != null && !props.getSpSigningKeyPem().isBlank()
                && props.getSpSigningCertPem() != null && !props.getSpSigningCertPem().isBlank()) {
            PrivateKey key = PemUtils.parsePrivateKey(props.getSpSigningKeyPem());
            X509Certificate cert = PemUtils.parseCertificate(props.getSpSigningCertPem());
            SamlBuilders.signObject(req, key, cert);
        }

        String samlRequest = SamlBuilders.toBase64Xml(req);

        String redirect = props.getIdpSsoUrl()
                + "?SAMLRequest=" + URLEncoder.encode(samlRequest, StandardCharsets.UTF_8)
                + "&RelayState=" + URLEncoder.encode(relayState, StandardCharsets.UTF_8);

        response.setStatus(302);
        response.setHeader("Location", redirect);
    }
}

package com.example.samlsp.web;

import com.example.samlsp.saml.SamlProperties;
import com.example.samlsp.saml.SamlResponseValidator;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.MediaType;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.util.HashMap;
import java.util.Map;

@RestController
public class SamlAcsController {

    private final SamlProperties props;
    private final SamlResponseValidator validator;

    public SamlAcsController(SamlProperties props) {
        this.props = props;
        this.validator = new SamlResponseValidator(props);
    }

    @PostMapping(value = "/saml/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE, produces = MediaType.APPLICATION_JSON_VALUE)
    public Map<String, Object> acs(@RequestParam("SAMLResponse") String samlResponse,
                                   @RequestParam(value = "RelayState", required = false) String relayState,
                                   HttpServletRequest request) {
        SamlResponseValidator.ValidatedSaml validated = validator.validatePostResponse(samlResponse);

        HttpSession session = request.getSession(true);
        session.setAttribute("saml.subject", validated.subjectNameId());
        session.setAttribute("saml.responseId", validated.responseId());
        session.setAttribute("saml.assertionId", validated.assertionId());
        session.setAttribute("saml.relayState", relayState);

        Map<String, Object> out = new HashMap<>();
        out.put("authenticated", true);
        out.put("subject", validated.subjectNameId());
        out.put("relayState", relayState);
        return out;
    }
}

