@RestController
public class MeController {

    @GetMapping(value = "/me", produces = MediaType.APPLICATION_JSON_VALUE)
    public Map<String, Object> me(HttpServletRequest request) {
        Map<String, Object> out = new HashMap<>();
        out.put("subject", request.getSession(false) == null ? null : request.getSession(false).getAttribute("saml.subject"));
        out.put("responseId", request.getSession(false) == null ? null : request.getSession(false).getAttribute("saml.responseId"));
        out.put("assertionId", request.getSession(false) == null ? null : request.getSession(false).getAttribute("saml.assertionId"));
        return out;
    }
}

